import { HttpEventType } from '@angular/common/http';
import { Component } from '@angular/core';
import { Router } from '@angular/router';
import { ResumeResponse } from '../../../core/models/resume.model';
import { ResumeService } from '../../../core/services/resume.service';

@Component({
  selector: 'app-upload-resume',
  templateUrl: './upload-resume.component.html'
})
export class UploadResumeComponent {
  selectedFile: File | null = null;
  uploadProgress = 0;
  uploading = false;
  error = '';

  constructor(
    private readonly resumeService: ResumeService,
    private readonly router: Router
  ) {
  }

  onFileSelected(event: Event): void {
    const input = event.target as HTMLInputElement;
    this.selectedFile = input.files?.[0] ?? null;
    this.error = '';
  }

  upload(): void {
    if (!this.selectedFile) {
      this.error = 'Please choose a PDF resume first.';
      return;
    }

    this.uploading = true;
    this.uploadProgress = 0;
    this.error = '';

    this.resumeService.uploadResumeWithProgress(this.selectedFile).subscribe({
      next: (event) => {
        if (event.type === HttpEventType.UploadProgress && event.total) {
          this.uploadProgress = Math.round((event.loaded / event.total) * 100);
        }

        if (event.type === HttpEventType.Response) {
          const resume = event.body as ResumeResponse;
          this.router.navigate(['/resume', resume.id, 'analysis']);
        }
      },
      error: (error: { error?: { message?: string } }) => {
        this.uploading = false;
        this.error = error.error?.message ?? 'Resume upload failed.';
      }
    });
  }
}
<div class="mx-auto max-w-4xl space-y-6">
  <div class="glass-panel p-8">
    <p class="text-sm font-semibold uppercase tracking-[0.28em] text-poppy">Step 1</p>
    <h2 class="section-title mt-3 text-4xl">Upload your resume PDF</h2>
    <p class="mt-4 max-w-2xl text-base leading-7 text-ink/65">
      Keep the first version constrained: one PDF, one parse, one analysis, and one job-matching pass.
    </p>

    <div class="mt-8 rounded-[2rem] border border-dashed border-ink/15 bg-white/60 p-8">
      <input type="file" accept=".pdf,application/pdf" (change)="onFileSelected($event)" class="field">
      <p class="mt-4 text-sm text-ink/60">
        Selected: <span class="font-semibold text-ink">{{ selectedFile?.name || 'No file selected' }}</span>
      </p>
    </div>

    <div *ngIf="uploading" class="mt-6">
      <div class="h-3 overflow-hidden rounded-full bg-ink/10">
        <div class="h-full rounded-full bg-poppy transition-all" [style.width.%]="uploadProgress"></div>
      </div>
      <p class="mt-3 text-sm font-semibold text-ink/65">Uploading... {{ uploadProgress }}%</p>
    </div>

    <p *ngIf="error" class="mt-4 rounded-2xl bg-poppy/10 px-4 py-3 text-sm font-medium text-poppy">{{ error }}</p>

    <div class="mt-8 flex gap-3">
      <button class="btn-primary" (click)="upload()" [disabled]="uploading">Upload Resume</button>
      <a routerLink="/dashboard" class="btn-secondary">Back to Dashboard</a>
    </div>
  </div>
</div>
